//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagetransfer_testimport(	"context"	"fmt"	"testing"	"github.com/aws/aws-sdk-go/aws"	"github.com/aws/aws-sdk-go/service/transfer"	"github.com/hashicorp/aws-sdk-go-base/v2/awsv1shim/v2/tfawserr"	sdkacctest"github.com/hashicorp/terraform-plugin-testing/helper/acctest"	"github.com/hashicorp/terraform-plugin-testing/helper/resource"	"github.com/hashicorp/terraform-plugin-testing/terraform"	"github.com/hashicorp/terraform-provider-aws/internal/acctest"	"github.com/hashicorp/terraform-provider-aws/internal/conns"	tftransfer"github.com/hashicorp/terraform-provider-aws/internal/service/transfer")functestAccSSHKey_basic(t*testing.T){	ctx:=acctest.Context(t)	varconftransfer.SshPublicKey	rName:=sdkacctest.RandomWithPrefix(acctest.ResourcePrefix)	resourceName:="aws_transfer_ssh_key.test"	publicKey,_,err:=sdkacctest.RandSSHKeyPair(acctest.DefaultEmailAddress)	iferr!=nil{		t.Fatalf("errorgeneratingrandomSSHkey:%s",err)	}	resource.Test(t,resource.TestCase{		PreCheck:func(){acctest.PreCheck(ctx,t);testAccPreCheck(ctx,t)},		ErrorCheck:acctest.ErrorCheck(t,transfer.EndpointsID),		ProtoV5ProviderFactories:acctest.ProtoV5ProviderFactories,		CheckDestroy:testAccCheckSSHKeyDestroy(ctx),		Steps:[]resource.TestStep{			{				Config:testAccSSHKeyConfig_basic(rName,publicKey),				Check:resource.ComposeTestCheckFunc(					testAccCheckSSHKeyExists(ctx,resourceName,&conf),					resource.TestCheckResourceAttrPair(resourceName,"server_id","aws_transfer_server.test","id"),					resource.TestCheckResourceAttrPair(resourceName,"user_name","aws_transfer_user.test","user_name"),					resource.TestCheckResourceAttr(resourceName,"body",publicKey),				),			},			{				ResourceName:resourceName,				ImportState:true,				ImportStateVerify:true,			},		},	})}functestAccCheckSSHKeyExists(ctxcontext.Context,nstring,res*transfer.SshPublicKey)resource.TestCheckFunc{	returnfunc(s*terraform.State)error{		rs,ok:=s.RootModule().Resources[n]		if!ok{			returnfmt.Errorf("Notfound:%s",n)		}		ifrs.Primary.ID==""{			returnfmt.Errorf("NoTransferSshPublicKeyIDisset")		}		conn:=acctest.Provider.Meta().(*conns.AWSClient).TransferConn(ctx)		serverID,userName,sshKeyID,err:=tftransfer.DecodeSSHKeyID(rs.Primary.ID)		iferr!=nil{			returnfmt.Errorf("errorparsingTransferSSHPublicKeyID:%s",err)		}		describe,err:=conn.DescribeUserWithContext(ctx,&transfer.DescribeUserInput{			ServerId:aws.String(serverID),			UserName:aws.String(userName),		})		iferr!=nil{			returnerr		}		for_,sshPublicKey:=rangedescribe.User.SshPublicKeys{			ifsshKeyID==*sshPublicKey.SshPublicKeyId{				*res=*sshPublicKey				returnnil			}		}		returnfmt.Errorf("TransferSshPublicKeydoesn'texists.")	}}functestAccCheckSSHKeyDestroy(ctxcontext.Context)resource.TestCheckFunc{	returnfunc(s*terraform.State)error{		conn:=acctest.Provider.Meta().(*conns.AWSClient).TransferConn(ctx)		for_,rs:=ranges.RootModule().Resources{			ifrs.Type!="aws_transfer_ssh_key"{				continue			}			serverID,userName,sshKeyID,err:=tftransfer.DecodeSSHKeyID(rs.Primary.ID)			iferr!=nil{				returnfmt.Errorf("errorparsingTransferSSHPublicKeyID:%w",err)			}			describe,err:=conn.DescribeUserWithContext(ctx,&transfer.DescribeUserInput{				UserName:aws.String(userName),				ServerId:aws.String(serverID),			})			iftfawserr.ErrCodeEquals(err,transfer.ErrCodeResourceNotFoundException){				continue			}			iferr!=nil{				returnerr			}			for_,sshPublicKey:=rangedescribe.User.SshPublicKeys{				ifsshKeyID==*sshPublicKey.SshPublicKeyId{					returnfmt.Errorf("TransferSSHPublicKeystillexists")				}			}		}		returnnil	}}functestAccSSHKeyConfig_basic(rName,publicKeystring)string{	returnfmt.Sprintf(`resource"aws_transfer_server""test"{identity_provider_type="SERVICE_MANAGED"}resource"aws_iam_role""test"{name=%[1]qassume_role_policy=<<EOF{"Version":"2012-10-17","Statement":[{"Effect":"Allow","Principal":{"Service":"transfer.amazonaws.com"},"Action":"sts:AssumeRole"}]}EOF}resource"aws_iam_role_policy""test"{name=%[1]qrole=aws_iam_role.test.idpolicy=<<POLICY{"Version":"2012-10-17","Statement":[{"Sid":"AllowFullAccesstoS3","Effect":"Allow","Action":["s3:*"],"Resource":"*"}]}POLICY}resource"aws_transfer_user""test"{server_id=aws_transfer_server.test.iduser_name="tftestuser"role=aws_iam_role.test.arn}resource"aws_transfer_ssh_key""test"{server_id=aws_transfer_server.test.iduser_name=aws_transfer_user.test.user_namebody="%[2]s"}`,rName,publicKey)}